// LOCK SLOT - Prepara datos del evento, incluye doctor si aplica
const slot    = $json.chosen_slot;
const patient = $json.sender_name    || "Paciente";
const phone   = $json.contact_phone  || "No disponible";
const clinicName = $json.clinic_name || $json.slot_clinic_name || "Clinica";
const nl      = String.fromCharCode(10);

// Detect service from original message
const src_msg = ($json.original_appointment_message || "").toLowerCase();
var service = "Consulta dental";
if (src_msg.includes("limpieza"))                               service = "Limpieza dental";
else if (src_msg.includes("blanqueamiento"))                    service = "Blanqueamiento dental";
else if (src_msg.includes("ortodoncia"))                        service = "Ortodoncia";
else if (src_msg.includes("extraccion")||src_msg.includes("extracción")) service = "Extraccion dental";
else if (src_msg.includes("endodoncia")||src_msg.includes("conducto"))   service = "Endodoncia";
else if (src_msg.includes("implante"))                          service = "Implante dental";
else if (src_msg.includes("revision")||src_msg.includes("revisión")||src_msg.includes("chequeo")) service = "Revision dental";
else if (src_msg.includes("dolor")||src_msg.includes("urgencia")) service = "Urgencia dental";

// Doctor from chosen slot
var doctor_id   = slot.doctor_id   || null;
// Demo mode: obtener datos del prospecto desde Chatwoot
var isDemoMode = ($json.bot_config || {}).demo_mode === true;
if (isDemoMode) {
  var demoName = patient;
  var demoClinic = "";
  try {
    var bcfg = $json.bot_config || {};
    var convResp = await this.helpers.httpRequest({
      method: "GET",
      url: "https://chat.redsolucionesti.com/api/v1/accounts/" + $json.account_id + "/conversations/" + $json.conversation_id,
      headers: { "api_access_token": bcfg.chatwoot_api_token }
    });
    var demoAttrs = (convResp.custom_attributes || {});
    if (demoAttrs.demo_name) demoName = demoAttrs.demo_name;
    if (demoAttrs.demo_clinic) demoClinic = demoAttrs.demo_clinic;
  } catch(e) {}
  service = "Demo SofIA" + (demoClinic ? " - " + demoClinic : "");
  patient = demoName + (demoClinic ? " (" + demoClinic + ")" : "");
}
var doctor_name = slot.doctor_name || null;

return [{
  json: Object.assign({}, $json, {
    event_summary:     service + " - " + patient,
    event_description: "Paciente: " + patient + nl + "Telefono: " + phone + nl
                     + "Servicio: " + service
                     + (doctor_name ? nl + "Doctor: " + doctor_name : "") + nl + nl
                     + "Agendado automaticamente por SofIA Bot",
    event_start:    slot.start_iso,
    event_end:      slot.end_iso,
    event_location: clinicName,
    service_type:   service,
    doctor_id:      doctor_id,
    doctor_name:    doctor_name
  })
}];

// CONFIRM APPOINTMENT TO PATIENT — professional message with emoji and structure
const original_data = $node["Lock de Slot"].json;
const slot          = original_data.chosen_slot;
const service       = original_data.service_type || "Consulta dental";
const clinic_name   = original_data.clinic_name || original_data.slot_clinic_name || "nuestra clinica";
const doctor_name   = original_data.doctor_name || null;
const clinic_phone  = (original_data.bot_config && original_data.bot_config.phone)
  ? original_data.bot_config.phone : (original_data.slot_clinic_phone || null);
const nl = String.fromCharCode(10);

const doctor_line = doctor_name   ? (nl + "\ud83d\udc68\u200d\u2695\ufe0f " + doctor_name) : "";
const phone_line  = clinic_phone  ? (nl + nl + "\ud83d\udcde Si necesitas cambios, llamanos: *" + clinic_phone + "*") : "";

const confirmation_message =
    "\u2705 *\u00a1Cita confirmada!*" + nl + nl +
    "\ud83d\udcc5 *" + slot.date + "* a las *" + slot.time + "*" + nl +
    "\ud83c\udfe5 " + clinic_name + nl +
    "\ud83e\uddb7 " + service +
    doctor_line + nl + nl +
    "\u23f0 Te recomendamos llegar *10 minutos antes*." +
    phone_line + nl + nl +
    "\u00a1Te esperamos! \ud83d\ude0a";

const appt_id = $json.appointment_id || "N/A";
const internal_note = "CITA AGENDADA POR SOFIA" + nl + nl
  + "Fecha/Hora: " + slot.date + " a las " + slot.time + nl
  + "Servicio: " + service + nl
  + (doctor_name ? "Doctor: " + doctor_name + nl : "")
  + "Paciente: " + (original_data.sender_name || "Paciente") + nl
  + "Telefono: " + (original_data.contact_phone || "-") + nl
  + "Appointment ID: " + appt_id + nl + nl
  + "SofIA — Confirmacion automatica";

// Send T09 dynamic quick-reply with appointment details + action buttons
const botConfigConf = original_data.bot_config || {};
if (botConfigConf.twilio_account_sid && botConfigConf.twilio_appointment_content_sid && original_data.contact_phone) {
  var _toConf = original_data.contact_phone;
  if (!_toConf.startsWith("whatsapp:")) _toConf = "whatsapp:" + _toConf;
  var _authConf = Buffer.from(botConfigConf.twilio_account_sid + ":" + botConfigConf.twilio_auth_token).toString("base64");
  var _apptSummary = "🏥 " + service + nl + "📅 " + slot.date + " a las " + slot.time;
  if (doctor_name) _apptSummary += nl + "👨‍⚕️ " + doctor_name;
  var _t09Bd = ["From=" + encodeURIComponent(botConfigConf.twilio_from),
    "To=" + encodeURIComponent(_toConf),
    "ContentSid=" + encodeURIComponent(botConfigConf.twilio_appointment_content_sid),
    "ContentVariables=" + encodeURIComponent(JSON.stringify({ "1": _apptSummary }))
  ].join("&");
  try {
    await this.helpers.httpRequest({ method: "POST",
      url: "https://api.twilio.com/2010-04-01/Accounts/" + botConfigConf.twilio_account_sid + "/Messages.json",
      headers: { "Authorization": "Basic " + _authConf, "Content-Type": "application/x-www-form-urlencoded" },
      body: _t09Bd });
  } catch(_et09) {}
}

return [{
  json: Object.assign({}, original_data, {
    confirmation_message: confirmation_message,
    internal_note:        internal_note,
    appointment_id:       appt_id,
    event_created:        true
  })
}];

// ACTUALIZAR ATTRIBUTES EXITO
const ctx = $node["Lock de Slot"].json;
const account_id = ctx.account_id;
const conversation_id = ctx.conversation_id;
const token = $node["Merge Clinic Data"].json.chatwoot_api_token;
const baseUrl = 'https://chat.redsolucionesti.com/api/v1/accounts/' + account_id;
const headers = { 'api_access_token': token, 'Content-Type': 'application/json' };

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: baseUrl + '/conversations/' + conversation_id,
    headers: headers,
    body: {
      custom_attributes: {
        sofia_phase: 'PHASE_4_COMPLETE',
        awaiting_slot_confirmation: 'false',
        appointment_confirmed: 'true',
        bot_interaction_count: (ctx.bot_interaction_count || 0) + 1
      }
    }
  });
} catch(e) {
  console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'ATTRS_UPDATE_ERROR', error: e.message }));
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/conversations/' + conversation_id + '/labels',
    headers: headers,
    body: { labels: [] }
  });
} catch(e) {
  console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'LABEL_CLEAR_ERROR', error: e.message }));
}

return [{
  json: {
    account_id: account_id,
    conversation_id: conversation_id,
    clinic_id: ctx.clinic_id,
    intent: ctx.intent,
    attrs_updated: true,
    label_cleared: true
  }
}];

// ── Retry Library (exponential backoff + jitter) ──────────────────────────
const withRetry = async (fn, opts = {}) => {
    const {
        attempts   = 3,
        baseMs     = 1000,      // 1s base
        maxMs      = 30000,     // 30s max wait
        noRetryOn  = [],        // status codes o strings → no reintentar
        onRetry    = null       // callback(attempt, error)
    } = opts;

    let lastError;
    for (let i = 0; i < attempts; i++) {
        try {
            return await fn();
        } catch(e) {
            lastError = e;
