}

if (intent === "DEMO_PLAN_INFO") {
  const plan = ctx._demo_plan || "";
  var planText = "";
  if (plan === "basico") { planText = "\uD83D\uDFE2 *Plan B\u00E1sico \u2014 S/.299/mes*\n\n\u2705 Agendamiento autom\u00E1tico\n\u2705 Respuestas con IA a preguntas frecuentes\n\u2705 Base de conocimiento personalizada\n\u2705 1 n\u00FAmero de WhatsApp\n\u2705 Panel Chatwoot incluido\n\u2705 Hasta 500 conversaciones/mes\n\nIdeal para cl\u00EDnicas que est\u00E1n empezando con automatizaci\u00F3n.\n\n\u00BFQuieres una demo personalizada? \uD83E\uDD1D"; }
  else if (plan === "pro") { planText = "\uD83D\uDD35 *Plan Pro \u2014 S/.499/mes* \u2B50 (m\u00E1s popular)\n\nTodo del B\u00E1sico, m\u00E1s:\n\u2705 Recordatorios autom\u00E1ticos 24h antes\n\u2705 Reportes mensuales por email\n\u2705 Soporte prioritario v\u00EDa WhatsApp\n\u2705 Hasta 1,500 conversaciones/mes\n\u2705 M\u00E9tricas avanzadas\n\n\u00BFTe agendamos una demo del Plan Pro? \uD83D\uDCC5"; }
  else if (plan === "enterprise") { planText = "\uD83D\uDFE3 *Plan Enterprise \u2014 desde S/.799/mes*\n\nPara grupos y cadenas dentales:\n\u2705 M\u00FAltiples cl\u00EDnicas en un panel\n\u2705 M\u00FAltiples n\u00FAmeros de WhatsApp\n\u2705 API para integraci\u00F3n con tu sistema\n\u2705 Onboarding dedicado + capacitaci\u00F3n\n\u2705 Soporte 24/7\n\u2705 Conversaciones ilimitadas\n\nCont\u00E1ctanos para cotizaci\u00F3n personalizada \uD83E\uDD1D"; }
  else if (plan === "comparar") { planText = "\uD83D\uDCCB *Comparativa de planes*\n\n\uD83D\uDFE2 B\u00E1sico \u2192 S/.299/mes \u2192 500 conversaciones\n\uD83D\uDD35 Pro \u2192 S/.499/mes \u2192 1,500 conversaciones\n\uD83D\uDFE3 Enterprise \u2192 desde S/.799 \u2192 Ilimitadas\n\n\u2728 Sin contrato de permanencia. Cancela cuando quieras.\n\uD83D\uDCA1 Descuento 15% pagando 6 meses | 25% pagando 1 a\u00F1o\n\n\u00BFHablamos con un asesor para elegir el mejor? \uD83E\uDD1D"; }
  else { planText = "\uD83D\uDCB0 *Planes de SofIA AI*\n\n\uD83D\uDFE2 Plan B\u00E1sico: S/.299/mes \u2014 500 conversaciones\n\uD83D\uDD35 Plan Pro: S/.499/mes \u2014 1,500 conversaciones \u2B50\n\uD83D\uDFE3 Enterprise: desde S/.799/mes \u2014 ilimitadas\n\nSin contrato. Cancela cuando quieras.\n\n\u00BFQuieres hablar con un asesor para elegir el mejor plan? \uD83E\uDD1D"; }
  await sendText.call(this, planText);
  await sendTwilioTemplate.call(this, botConfig.twilio_followup_content_sid, {});
  return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DEMO_PLAN_RESPONSE_SENT" }) }];
}

// ── New Demo Flow Engine ─────────────────────────────────────────────────
const flowConfig = botConfig.demo_flow || null;
if (!flowConfig || !flowConfig.nodes) {
  // No demo flow config — fallback
  return [{ json: ctx }];
}

// ── Lead capture state machine ───────────────────────────────────────────
if (intent === "DEMO_FLOW") {
  var leadState = convLabels.find(function(l) { return l.startsWith("df_lead_"); });
  if (leadState) {
    return await handleLeadCapture.call(this, "_LEAD_CAPTURE", null, flowConfig);
  }
}

// ── Resolve current state node ───────────────────────────────────────────
var currentNodeId = getDemoState() || flowConfig.start_node;
var currentNode = flowConfig.nodes[currentNodeId];

// ── DEMO_FLOW_START: show bienvenida ─────────────────────────────────────
if (intent === "DEMO_FLOW_START") {
  var startId = flowConfig.start_node;
  await sendDemoNode.call(this, startId, flowConfig);
  return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_BIENVENIDA_SENT", skip_ai: true }) }];
}

// ── DEMO_FLOW_CATCH_ALL: re-send current node ────────────────────────────
if (intent === "DEMO_FLOW_CATCH_ALL") {
  var catchNodeId = currentNodeId || flowConfig.catch_all_node;
  await sendText.call(this, "\uD83D\uDC49 Por favor elige una de las opciones del men\u00FA:");
  await sendDemoNode.call(this, catchNodeId, flowConfig);
  return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_CATCH_ALL_RESENT", skip_ai: true }) }];
}

// ── DEMO_FLOW: user selected pos_1..pos_5 ────────────────────────────────
if (intent === "DEMO_FLOW") {
  var pos = ctx.demo_pos;
  if (!currentNode || !pos) {
    await sendDemoNode.call(this, flowConfig.start_node, flowConfig);
    return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_FALLBACK_START", skip_ai: true }) }];
  }
  // Find selected option (pos is 1-based index)
  var selectedOption = currentNode.options[pos - 1] || null;
  if (!selectedOption) {
    await sendText.call(this, "\uD83D\uDC49 Por favor elige una de las opciones disponibles:");
    await sendDemoNode.call(this, currentNodeId, flowConfig);
    return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_INVALID_POS", skip_ai: true }) }];
  }

  // Execute action or navigate to next node
  var action = selectedOption.action || null;
  var nextNodeId = selectedOption.next || null;

  if (action === "_HUMAN") {
    await transitionToNode.call(this, null);
    await sendText.call(this, "👤 ¡Claro! Un asesor de SofIA AI se pondrá en contacto contigo en breve para resolver todas tus dudas.\n\n¡Gracias por tu interés!");
    try {
      await this.helpers.httpRequest({
        method: "POST",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/toggle_status",
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: JSON.stringify({ status: "pending" }),
        json: false
      });
    } catch(e) { console.error("_HUMAN toggle status error:", e.message); }
    // Private note so asesor has context
    try {
      await this.helpers.httpRequest({
        method: "POST",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/messages",
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: JSON.stringify({ content: "🤝 LEAD SOLICITA ASESOR (desde demo SofIA)\nContacto: " + (ctx.contact_phone || ctx.sender_name || "desconocido"), message_type: "outgoing", private: true }),
        json: false
      });
    } catch(e) {}
    return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_ACTION_HUMAN_SENT", skip_ai: true }) }];
  }

  if (action === "_CREATE_EVENT") {
    await transitionToNode.call(this, null);
    // DEMO BOOKING: collect lead info first, then show calendar day picker
    var _hasLeadData = convLabels.includes("lead_captured");
    if (!_hasLeadData) {
      // Lead info not collected yet — start multi-step form
      return await handleLeadCapture.call(this, "_LEAD_CAPTURE", null, flowConfig);
    }
    // Lead already captured → go straight to LP5 day picker
    await sendText.call(this, "\u{1F4C5} Genial! Elijamos el d\u00EDa para tu demo:");
    return await sendDemoBookingDayPicker.call(this, botConfig, ctx);
  }

  if (action === "_LEAD_CAPTURE" || action === "_LEAD_CAPTURE_START") {
    return await handleLeadCapture.call(this, action, selectedOption, flowConfig);
  }

  if (nextNodeId && flowConfig.nodes[nextNodeId]) {
    await sendDemoNode.call(this, nextNodeId, flowConfig);
    return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_NAV_" + nextNodeId.toUpperCase(), skip_ai: true }) }];
  }

  // No action, no next → go back to bienvenida
  await sendDemoNode.call(this, flowConfig.start_node, flowConfig);
  return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_FALLBACK_BIENVENIDA", skip_ai: true }) }];
}

// Fallback — should not reach here
return [{ json: ctx }];

// ============================================
// VALIDAR INPUT + DETECTAR CONTACTO NUEVO
// ============================================
const payload = $input.item.json.body || $input.item.json;

// Campos del evento
const event = payload.event;
const content = payload.content || '';
const conversation_id = payload.conversation?.id;
const inbox_id = payload.conversation?.inbox_id;
const clinic_id = payload.conversation?.custom_attributes?.clinic_id;
const patient_id = payload.conversation?.custom_attributes?.patient_id;
const contact_phone = payload.conversation?.contact_inbox?.source_id;
const contact_id = payload.sender?.id;
const channel_type = payload.conversation?.contact_inbox?.inbox?.channel_type;
const account_id = payload.account?.id || 2;
const message_type = payload.message_type;
const created_at = payload.created_at;

// Obtener contador de interacciones bot
const bot_count = payload.conversation?.custom_attributes?.bot_interaction_count || 0;
const last_bot_message = payload.conversation?.custom_attributes?.last_bot_message_at;
const contact_inboxes = payload.conversation?.contact_inbox;
const has_contact_inbox = !!contact_inboxes;

return [{
  json: {
    message_text: (content || '').trim(),
    conversation_id: conversation_id,
    inbox_id: inbox_id,
    inbox_id_api: 2,
    inbox_id_db: 3,
    clinic_id: clinic_id || 'default',
    patient_id: patient_id,
    contact_phone: contact_phone,
    contact_id: contact_id,
    account_id: account_id,
    message_type: message_type,
    message_timestamp: created_at,
    bot_interaction_count: bot_count,
    last_bot_message_at: last_bot_message,
    sender_name: payload.sender?.name || 'Paciente',
    sender_email: payload.sender?.email,
    conversation_status: payload.conversation?.status,
    has_contact_inbox: has_contact_inbox,
    channel_type: channel_type || 'Channel::WebWidget',
    raw_payload: payload
  }
}];

// WHATSAPP SAFE RULES - SofIA 24/7
const ctx           = $input.first().json;
const bot_count     = ctx.bot_interaction_count || 0;
const raw           = (ctx.message_text || "");
const message_lower = raw.toLowerCase();
// Normalize: remove accents, replace common typos
const msgNorm = message_lower.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

// Regla 1: Maximo 10 interacciones automaticas
if (bot_count >= 10) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "MAX_INTERACTIONS_PHASE1",
    escalation_message: "Te conecto con un agente de inmediato. Un momento." } }];
}

// Regla 2: Mensaje > 24h (muy antiguo)
const message_age_hours = (Date.now() - (ctx.message_timestamp * 1000)) / 3600000;
if (message_age_hours > 24) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "MESSAGE_TOO_OLD",
    escalation_message: "Te conecto con un agente." } }];
}

// Regla 3: Emergencias — normalized check (handles typos and variations)
const emergency_kws = [
  "emergencia","emrgencia","urgencia","urgente",
  "dolor fuerte","sangra","sangrado","mucho dolor","me duele mucho","duele mucho",
  "muela rota","golpe","accidente","hinchazon","infeccion","inflamacion","fiebre",
  "caida","fractura","trauma","absceso","quiste",
  "dolor de muela","me duele la muela","me duele una muela","dolor muela",
  "duele el diente","duele la muela","muela hinchada","cara hinchada",
  "no puedo dormir del dolor","llevo dias con dolor","tengo mucho dolor"
];
if (emergency_kws.some(function(kw) { return msgNorm.includes(kw); })) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "EMERGENCY_DETECTED",
    escalation_message: "\u26a0\ufe0f Entiendo que tienes molestias dentales. Te conecto con nuestro equipo de inmediato para atenderte.", priority: "urgent" } }];
}

// Regla 4: Opt-out explicito
const opt_out_kws = ["detente","ya no","basta","stop","cancelar bot","agente","humano","persona real","hablar con alguien","quiero hablar con"];
if (opt_out_kws.some(function(kw) { return message_lower.includes(kw); })) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "USER_OPT_OUT",
    escalation_message: "Entendido. Te conecto con un agente ahora mismo." } }];
}

// SofIA responde 24/7 sin restriccion de horario
return [{ json: { ...ctx, should_escalate: false, whatsapp_safe: true,
  debug_bot_count: bot_count, checked_at: new Date().toISOString() } }];

// NORMALIZAR OUTPUT DEL CLASIFICADOR
// Keyword path: context is intact in $json
if ($json.skip_ai === true && $json.intent) {
    const intent = $json.intent;
    // GREETING is now handled by ¿Es MENU o GREETING? — do NOT convert to INFO
    return [{ json: Object.assign({}, $json, { intent: intent, classified_at: new Date().toISOString(), phase: "PHASE_1_WITH_PRE_CLASSIFIER" }) }];
}

// AI path: restore context from Pre-Clasificador Keywords node
const ctx = $node["Pre-Clasificador Keywords"].json;
let intent_data = $json.output || $json;
if (typeof intent_data === "string") {
    try { intent_data = JSON.parse(intent_data); }
    catch(e) {
        const t = intent_data.toLowerCase();
        if (t.includes("create_event")) intent_data = { intent: "CREATE_EVENT", confidence: "low" };
        else if (t.includes("info"))   intent_data = { intent: "INFO",         confidence: "low" };
        else if (t.includes("payment")) intent_data = { intent: "PAYMENT",     confidence: "low" };
        else intent_data = { intent: "HUMAN", confidence: "low" };
    }
}
let intent = (intent_data.intent || "HUMAN").trim().toUpperCase();
let confidence = (intent_data.confidence || "low").toLowerCase();
const valid = ["CREATE_EVENT","INFO","PAYMENT","HUMAN"];
if (!valid.includes(intent)) { intent = "HUMAN"; confidence = "low"; }
return [{ json: Object.assign({}, ctx, { intent: intent, confidence: confidence, classified_at: new Date().toISOString(), phase: "PHASE_1_WITH_AI_CLASSIFIER" }) }];

// PREPARAR ESCALADO — pausa el bot en Supabase governance
const ctx = $json;
const escalationMsg = ctx.escalation_message
  || (ctx.bot_config && ctx.bot_config.escalation_message)
  || (ctx.intent === 'PAYMENT'
    ? 'Perfecto, te conecto con un asesor para ayudarte con el pago. Un momento por favor \ud83d\ude4f'
    : ctx.intent === 'HUMAN'
    ? 'Entendido! Te conecto con uno de nuestros asesores ahora mismo. Un momento \ud83d\ude4f'
    : 'Te conecto con nuestro equipo enseguida. Un momento por favor \ud83d\ude4f');

// Intentar pausar el bot en Supabase (fail-safe: no bloquea el flujo)
const govId = ctx.governance_conversation_id;
if (govId) {
  const SUPABASE_URL = $env.N8N_SUPABASE_URL;
  const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/rpc/pause_conversation',
      headers: {
        'apikey':        SERVICE_KEY,
        'Authorization': 'Bearer ' + SERVICE_KEY,
        'Content-Type':  'application/json'
      },
      body: {
        p_conversation_id: govId,
        p_clinic_id:       ctx.clinic_id,
        p_user_role:       'admin'
      },
      json: true
    });
    console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'BOT_PAUSED', gov_id: govId }));
  } catch(e) {
    // Non-fatal: log but continue with escalation
    console.warn(JSON.stringify({ ts: new Date().toISOString(), event: 'BOT_PAUSE_FAILED', error: e.message }));
  }
}



