    sender_name: ctx.sender_name, sender_email: ctx.sender_email,
    conversation_status: ctx.conversation_status,
    has_contact_inbox: ctx.has_contact_inbox, channel_type: ctx.channel_type,
    intent: ctx.intent, confidence: ctx.confidence,
    selected_slots: ctx.selected_slots || [],
    label_set: true, slots_stored: slots.length > 0
  }
}];

// ============================================
// PREPARE ESCALATION WITH SLOT CONTEXT
// ============================================
const slots = $json.offered_slots || [];

let escalation_note = 'Paciente solicitó agendar cita.\n\n';
escalation_note += 'Horarios ofrecidos:\n';

slots.forEach(slot => {
  escalation_note += `${slot.option_number}. ${slot.date} a las ${slot.time}\n`;
});

escalation_note += '\nEsperando respuesta del paciente para confirmar el horario.';

return [{
  json: {
    ...$json,
    escalation_message: 'Gracias. Un agente se pondrá en contacto contigo pronto para confirmar tu cita.',
    escalation_note: escalation_note,
    escalation_reason: 'PHASE3_SLOTS_OFFERED',
    should_escalate: true
  }
}];

// CHECK IF AWAITING SLOT CONFIRMATION
const validar_data = $node["Validar Input"].json;
const convLabels = (validar_data.raw_payload && validar_data.raw_payload.conversation && validar_data.raw_payload.conversation.labels) ? validar_data.raw_payload.conversation.labels : [];
const awaitingViaLabel = convLabels.includes("awaiting_slot");
const custom_attrs = (validar_data.raw_payload && validar_data.raw_payload.conversation) ? validar_data.raw_payload.conversation.custom_attributes : {};
const awaitingViaAttr = custom_attrs && custom_attrs.awaiting_slot_confirmation === "true";
const awaiting = awaitingViaLabel || awaitingViaAttr;

console.log(JSON.stringify({ ts: new Date().toISOString(), awaiting_label: awaitingViaLabel, labels: convLabels }));

let slots = [];
let original_message = '';
let slot_clinic_name = '';
let slot_clinic_phone = '';

if (awaiting) {
  try {
    const account_id = validar_data.account_id;
    const conversation_id = validar_data.conversation_id;
    const token = $node["Merge Clinic Data"].json.chatwoot_api_token;
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://chat.redsolucionesti.com/api/v1/accounts/' + account_id + '/conversations/' + conversation_id + '/messages',
      headers: { 'api_access_token': token }
    });
    const messages = resp.payload || [];
    const slotNotes = messages.filter(function(m) {
      return m.private && typeof m.content === 'string' && m.content.startsWith('SOFIA_SLOTS:');
    });
    if (slotNotes.length > 0) {
      const lastNote = slotNotes[slotNotes.length - 1];
      const raw = lastNote.content.replace('SOFIA_SLOTS:', '');
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        slots = parsed;
      } else {
        slots = parsed.slots || [];
        original_message = parsed.original_message || '';
        slot_clinic_name = parsed.clinic_name || '';
        slot_clinic_phone = parsed.clinic_phone || '';
      }
      console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_RETRIEVED', count: slots.length, orig: original_message.substring(0,40) }));
    } else {
      console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_NOTE_NOT_FOUND' }));
    }
  } catch(e) {
    console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_FETCH_ERROR', error: e.message }));
  }
}

// Si usuario pide otro dia, limpiar label y reiniciar scheduling
if ($json.day_change_request === true && awaiting) {
  try {
    await this.helpers.httpRequest({
      method: "POST",
      url: "https://chat.redsolucionesti.com/api/v1/accounts/" + validar_data.account_id + "/conversations/" + validar_data.conversation_id + "/labels",
      headers: { "api_access_token": $node["Merge Clinic Data"].json.chatwoot_api_token, "Content-Type": "application/json" },
      body: { labels: [] }, json: true
    });
  } catch(e) { /* non-fatal */ }
  return [{ json: { ...$json, slot_confirmation_pending: false, is_second_interaction: false, offered_slots: [], day_change_request: true } }];
}

return [{
  json: {
    ...$json,
    intent: $json.intent,
    confidence: $json.confidence,
    slot_confirmation_pending: awaiting && (
      $json.classified_by === 'SLOT_CONFIRMATION_DETECTOR' ||
      $json.classified_by === 'SLOT_AFFIRMATION_DETECTOR' ||
      $json.classified_by === 'DAY_CHANGE_DETECTOR' ||
      $json.classified_by === 'SLOT_LP_BTN' ||
      $json.classified_by === 'SLOT_BTN_LABEL_DETECTOR'
    ),
    offered_slots: slots,
    original_appointment_message: original_message,
    slot_clinic_name: slot_clinic_name,
    slot_clinic_phone: slot_clinic_phone,
    is_second_interaction: awaiting
  }
}];

// ============================================
// PROCESS USER'S SLOT SELECTION
// ============================================
const raw = ($json.message_text || '');
const message = raw.toLowerCase().trim();
const slots = $json.offered_slots || [];

if (slots.length === 0) {
    return [{
        json: {
            ...$json,
            slot_chosen: false,
            needs_clarification: true,
            error_reason: 'NO_SLOTS_IN_CONTEXT'
        }
    }];
}

// Normalize message for matching (handles accents)
const msgNorm = message.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

let chosen_slot = null;
let chosen_index = -1;

// Match by number or ordinal words
if (msgNorm.match(/\b1\b/) || msgNorm.includes('primer') || msgNorm.includes('uno') || msgNorm.includes('primero') || msgNorm.includes('primera')) {
    chosen_slot = slots[0]; chosen_index = 0;
} else if (msgNorm.match(/\b2\b/) || msgNorm.includes('segund') || msgNorm.includes('dos')) {
    chosen_slot = slots[1]; chosen_index = 1;
} else if (msgNorm.match(/\b3\b/) || msgNorm.includes('tercer') || msgNorm.includes('tres')) {
    chosen_slot = slots[2]; chosen_index = 2;
} else if (msgNorm.match(/\b4\b/) || msgNorm.includes('cuart') || msgNorm.includes('cuatro')) {
    chosen_slot = slots[3]; chosen_index = 3;
} else if (msgNorm.match(/\b5\b/) || msgNorm.includes('quint') || msgNorm.includes('cinco')) {
    chosen_slot = slots[4]; chosen_index = 4;
}

// If single affirmative with no number, pick slot 1
if (!chosen_slot) {
    const affirmatives = ["si","sip","yes","ok","dale","claro","listo","va","bueno","perfecto","de acuerdo","adelante","quiero ese","esa","ese"];
    if (affirmatives.includes(msgNorm) || affirmatives.some(function(a) { return msgNorm.startsWith(a + " ") || msgNorm === a; })) {
        chosen_slot = slots[0]; chosen_index = 0;
    }
}

// Try to match by day name
if (!chosen_slot) {
    const days = ['lunes', 'martes', 'miercoles', 'jueves', 'viernes', 'sabado', 'domingo'];
    for (let i = 0; i < slots.length; i++) {
        const slot_text = (slots[i].date || '').toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
        for (const day of days) {
            if (msgNorm.includes(day) && slot_text.includes(day)) {
                chosen_slot = slots[i]; chosen_index = i; break;
            }
        }
        if (chosen_slot) break;
    }
}

if (!chosen_slot) {
    return [{
        json: {
            ...$json,
            slot_chosen: false,
            needs_clarification: true,
            error_reason: 'SLOT_NOT_IDENTIFIED'
        }
    }];
}

return [{
    json: {
        ...$json,
        slot_chosen: true,
        chosen_slot: chosen_slot,
        chosen_slot_index: chosen_index + 1,
        needs_clarification: false
    }
}];

