            url: `${SUPABASE_URL}/rest/v1/rpc/${rpcName}`,
            headers: {
                'apikey':        SERVICE_KEY,
                'Authorization': 'Bearer ' + SERVICE_KEY,
                'Content-Type':  'application/json'
            },
            body,
            json: true
        });
    }, {
        attempts,
        baseMs: 500,
