function parseBotConfig(bc) {
  if (!bc || typeof bc === 'undefined') return {};
  if (typeof bc === 'object' && bc !== null && bc['0'] === undefined) return bc;
  if (typeof bc === 'string') {
    try { return JSON.parse(bc); } catch(e) { return {}; }
  }
  if (typeof bc === 'object' && bc !== null && bc['0'] !== undefined) {
    const keys = Object.keys(bc).sort(function(a, b) { return Number(a) - Number(b); });
    let bcStr = keys.map(function(k) { return bc[k]; }).join('');
    try { return JSON.parse(bcStr); } catch(e) {}
    // Find valid JSON end by tracking brace depth (handles trailing garbage from Supabase)
    let depth = 0, inStr = false, esc = false, validEnd = -1;
    for (let i = 0; i < bcStr.length; i++) {
      const c = bcStr[i];
      if (esc) { esc = false; continue; }
      const backslash = String.fromCharCode(92);
      if (c === backslash && inStr) { esc = true; continue; }
      if (c === '"') { inStr = !inStr; continue; }
      if (!inStr) {
        if (c === '{' || c === '[') depth++;
        if (c === '}' || c === ']') { depth--; if (depth === 0) { validEnd = i; break; } }
      }
    }
    if (validEnd > 0 && validEnd < bcStr.length - 1) bcStr = bcStr.substring(0, validEnd + 1);
    try { return JSON.parse(bcStr); } catch(e) { return {}; }
  }
  return {};
}

